    func TestTreeDuplicatePath(t *testing.T) {
    	tree := &node{}

    	routes := [...]string{
    		"/",
    		"/doc/",
    		"/src/*filepath",
    		"/search/:query",
    		"/user_:name",
    	}
    	for _, route := range routes {
    		recv := catchPanic(func() {
    			tree.addRoute(route, fakeHandler(route))
    		})
    		if recv != nil {
    			t.Fatalf("panic inserting route '%s': %v", route, recv)
    		}

    		// Add again
    		recv = catchPanic(func() {
    			tree.addRoute(route, nil)
    		})
    		if recv == nil {
